// Get form inputs
const sector = $('Course Details Form').first().json['Sector'];
const title = $('Course Details Form').first().json['Course Title'];
const description = $('Course Details Form').first().json['Course Description'];
const level = $('Course Details Form').first().json['WSQ Level'];
const numLUs = parseInt($('Course Details Form').first().json['Number of Learning Units']);
const duration = $('Course Details Form').first().json['Total Training Duration (hours)'];
const deliveryMode = $('Course Details Form').first().json['Delivery Mode'];

// Get TSC data
const tscData = $input.first().json;
const sectorTSCs = tscData.sectors[sector] || [];

// Keyword matching
const searchText = (title + ' ' + description).toLowerCase();
const keywords = searchText
  .split(/[\s,;/&+.()]+/)
  .filter(w => w.length > 2)
  .filter(w => !['and', 'the', 'for', 'with', 'using', 'from', 'into', 'that', 'this', 'will', 'can', 'are', 'how'].includes(w));

const scored = sectorTSCs.map(tsc => {
  const skillText = (tsc.skill + ' ' + (tsc.parent || '')).toLowerCase();
  const kaText = [...(tsc.knowledge || []), ...(tsc.abilities || [])].join(' ').toLowerCase();
  const skillMatches = keywords.filter(kw => skillText.includes(kw));
  const kaMatches = keywords.filter(kw => kaText.includes(kw));
  return { ...tsc, score: skillMatches.length * 3 + kaMatches.length };
}).filter(tsc => tsc.score > 0)
  .sort((a, b) => b.score - a.score);

// Take top 5 TSC matches
const topTSCs = scored.slice(0, 5);

// Include top 3 CCS
const topCCS = (tscData.ccs || []).slice(0, 3);

return [{
  json: {
    sector, title, description, level, numLUs, duration, deliveryMode,
    matchedTSCs: topTSCs.map(t => ({
      code: t.code, skill: t.skill, level: t.level,
      knowledge: t.knowledge || [], abilities: t.abilities || []
    })),
    matchedCCS: topCCS.map(c => ({
      code: c.code, skill: c.skill,
      knowledge: c.knowledge || [], abilities: c.abilities || []
    }))
  }
}];

